-- Addon namespace
local _, Private = ...
local L = Private.Libs.ACL

-- Global environment
local _G = _G

-- Details profiles
function Private:Setup_Details(installer)
	if not Private.IsAddOnLoaded('Details') then Private:Print('Details ' .. L["is not installed or enabled."]) return end

	-- Global dbs
	local dev, scaled = Private.Addon.db.global.dev, Private.Addon.db.global.scaled

	-- Profile name
	local name = (dev and 'Luckyone') or 'Luckyone ' .. Private.Version

	-- Profile string
	local profileString = (scaled and [[D!ProfileV2-]])
	or [[D!ProfileV2-]]

	-- Profile import
	Details:ImportProfile(profileString, name)

	-- Apply the profile
	if Details:GetCurrentProfileName() ~= name then
		Details:ApplyProfile(name)
	end

	-- Load the profile on all characters
	Details.always_use_profile = true
	Details.always_use_profile_name = name

	if installer then
		_G.LuckyoneInstallStepComplete:ShowMessage(L["Details profile has been set."])
	end

	Private:Print(L["Details profile has been set."])
end
